[['eq 0 ]; then\n    echo "Usage: $0 "Post Title""\n    exit 1\nfi\n\nTITLE="$1"\nDATE=$(date +%Y-%m-%d)\nDATE_DISPLAY=$(date +%B %-d, %Y)\nSLUG=$(echo "$TITLE" | tr', ['upper:]\' \'[:lower:]\' | tr -s \' \' \'-\' | sed \'s/[^a-z0-9-]//g\')\nFILEPATH="blog/$SLUG.html"\n\n# Check if file already exists\nif [ -f "$FILEPATH'], 'then\n    echo "Error: $FILEPATH already exists"\n    exit 1\nfi\n\ncat > "$FILEPATH" << \'EOF\'\n<!DOCTYPE html>\n<html lang="en">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content=', 'width=device-width, initial-scale=1">\n    <title>\'"$TITLE"\' | Siesta Free Ride</title>\n    <meta name="description" content="Your article description here">\n    <script src="https://cdn.tailwindcss.com', 'script>\n    <script>\n        tailwind.config = {\n            theme: {\n                extend: {\n                    colors: {\n                        brand: \'#0077b6\',\n                        accent: \'#00b4d8\'\n                    }\n                }\n            }\n        }\n    </script>\n    <style>\n        .cursive-text {\n            font-family: cursive, "Brush Script MT', 'Lucida Handwriting', 'serif;\n            font-style: italic;\n            color: #00b4d8;\n        }\n        @media (max-width: 768px) {\n            .cursive-text {\n                font-size: 2rem;\n            }\n        }\n    </style>\n</head>\n<body class="bg-gray-50">\n    <header class="sticky top-0 z-50 bg-white shadow-md">\n        <div class="max-w-6xl mx-auto px-4 py-3 flex items-center justify-between">\n            <div class="flex items-center gap-3">\n                <img src="/assets/logo.png" alt="Siesta Free Ride" class="h-24">\n                <span class="cursive-text text-3xl font-bold text-brand" style=', 'text-shadow: -1px -1px 0 #000, 1px -1px 0 #000, -1px 1px 0 #000, 1px 1px 0 #000;">Siesta Free Ride</span>\n            </div>\n            <nav class="hidden md:flex gap-6">\n                <a href="/" class="hover:text-brand">Home</a>\n                <a href="/blog.html" class="hover:text-brand">Blog</a>\n                <a href="/contact.html" class="bg-brand text-white px-4 py-1.5 rounded-md">Book Now</a>\n            </nav>\n            <button class="md:hidden text-2xl" onclick="document.getElementById(\'mobile-menu\').classList.toggle(\'hidden\')">\n                &#9776;\n            </button>\n        </div>\n        <div id="mobile-menu" class="md:hidden hidden border-t bg-white">\n            <div class="px-4 py-3 space-y-3">\n                <a href="/" class="block hover:text-brand">Home</a>\n                <a href="/blog.html" class="block text-brand font-medium">Blog</a>\n                <a href="/contact.html" class="block">Book Now</a>\n            </div>\n        </div>\n    </header>\n\n    <main class="max-w-4xl mx-auto px-4 py-12">\n        <article>\n            <div class="mb-8">\n                <a href="/blog.html" class="text-brand font-medium">&larr; Back to Blog</a>\n            </div>\n            \n            <header class="mb-10">\n                <h1 class="text-4xl md:text-5xl font-bold mb-4>\'"$TITLE"\'</h1>\n                <div class="flex items-center gap-4 text-gray-500">\n                    <span>\'"$DATE_DISPLAY\'"</span>\n                    <span>&bull;</span>\n                    <span>5 min read</span>\n                </div>\n            </header>\n\n            <div class="prose prose-lg max-w-none">\n                <p class="lead text-xl text-gray-700 mb-8">Your article lead paragraph goes here...</p>\n\n                <h2 class="text-2xl font-bold mt-10 mb-4">Section 1</h2>\n                <p>Your content here...</p>\n\n                <h2 class="text-2xl font-bold mt-10 mb-4">Section 2</h2>\n                <p>Your content here...</p>\n\n                <div class="bg-gray-100 p-6 rounded-lg mt-12">\n                    <h3 class="text-xl font-bold mb-3', 'Need a Ride?</h3>\n                    <p>Exploring Siesta Key is easier when you don\'t have to worry about parking, directions, or designated drivers. <strong>Siesta Free Ride</strong> provides reliable, friendly transportation throughout the island and to/from SRQ Airport.</p>\n                    <p class="mt-3"><a href="/contact.html" class="bg-brand text-white px-6 py-3 rounded-md font-medium inline-block">Book Your Ride Today &rarr;</a></p>\n                    <p class="mt-3 text-lg font-medium">Or call/text: <a href="tel:9416008380" class="text-brand">941&#8209;600&#8209;8380</a></p>\n                </div>\n            </div>\n        </article>\n    </main>\n\n    <footer class="bg-gray-900 text-gray-200 py-8 mt-12">\n        <div class="max-w-6xl mx-auto px-4 text-center">\n            <p>&copy; <span id="yr"></span> Siesta Free Ride. <a href="/" class="text-accent">Home</a></p>\n        </div>\n    </footer>\n\n    <script>\n        document.getElementById(\'yr\').textContent = new Date().getFullYear();\n    </script>\n</body>\n</html>\nEOF\n\necho "Created: $FILEPATH"\necho "', 'echo "Next steps:"\necho "1. Edit the content in $FILEPATH"\necho "2. Update the meta description in <head>"\necho "3. Add internal links if needed"\necho "', 'echo', 'When ready, run:"\necho "git add $FILEPATH && git commit -m \'Add blog post: $TITLE\' && git push']]